"""
CollaborativeDesignSuite - A multi-agent collaborative design tool that enables
a team of designers to work together on a shared digital canvas.
"""

import uuid
import hashlib
import time
import threading
from enum import Enum
from dataclasses import dataclass, field
from typing import Optional


# --- Dependency Management ---

class FeatureState(Enum):
    NOT_READY = "not_ready"
    READY = "ready"
    ACTIVE = "active"


class DependencyManager:
    """Manages feature dependencies ensuring proper initialization order."""

    def __init__(self):
        self._features = {}
        self._dependencies = {}
        self._lock = threading.Lock()

    def register_feature(self, feature_name, dependencies=None):
        with self._lock:
            self._features[feature_name] = FeatureState.NOT_READY
            self._dependencies[feature_name] = dependencies or []

    def activate_feature(self, feature_name):
        with self._lock:
            if feature_name not in self._features:
                raise ValueError(f"Feature '{feature_name}' is not registered.")
            for dep in self._dependencies[feature_name]:
                if self._features.get(dep) != FeatureState.ACTIVE:
                    raise DependencyError(
                        f"Cannot activate '{feature_name}': "
                        f"dependency '{dep}' is not active."
                    )
            self._features[feature_name] = FeatureState.ACTIVE

    def is_active(self, feature_name):
        with self._lock:
            return self._features.get(feature_name) == FeatureState.ACTIVE

    def get_state(self, feature_name):
        with self._lock:
            return self._features.get(feature_name, FeatureState.NOT_READY)

    def check_dependency(self, feature_name):
        with self._lock:
            if feature_name not in self._features:
                raise ValueError(f"Feature '{feature_name}' is not registered.")
            for dep in self._dependencies[feature_name]:
                if self._features.get(dep) != FeatureState.ACTIVE:
                    return False
            return True


class DependencyError(Exception):
    """Raised when a feature dependency is not satisfied."""
    pass


# --- User Registration and Authentication ---

@dataclass
class User:
    user_id: str
    username: str
    password_hash: str
    email: str
    created_at: float = field(default_factory=time.time)
    is_active: bool = True


class AuthenticationSystem:
    """Handles user registration, login, and session management."""

    def __init__(self):
        self._users = {}
        self._sessions = {}
        self._lock = threading.Lock()

    @staticmethod
    def _hash_password(password, salt=None):
        if salt is None:
            salt = uuid.uuid4().hex
        hashed = hashlib.sha256((password + salt).encode()).hexdigest()
        return f"{salt}${hashed}"

    @staticmethod
    def _verify_password(password, stored_hash):
        salt, expected_hash = stored_hash.split("$", 1)
        actual_hash = hashlib.sha256((password + salt).encode()).hexdigest()
        return actual_hash == expected_hash

    def register(self, username, password, email):
        with self._lock:
            if username in self._users:
                raise ValueError(f"Username '{username}' is already taken.")
            user_id = str(uuid.uuid4())
            password_hash = self._hash_password(password)
            user = User(
                user_id=user_id,
                username=username,
                password_hash=password_hash,
                email=email,
            )
            self._users[username] = user
            return user

    def login(self, username, password):
        with self._lock:
            user = self._users.get(username)
            if not user:
                raise ValueError("Invalid username or password.")
            if not self._verify_password(password, user.password_hash):
                raise ValueError("Invalid username or password.")
            session_token = str(uuid.uuid4())
            self._sessions[session_token] = user.user_id
            return session_token

    def logout(self, session_token):
        with self._lock:
            if session_token in self._sessions:
                del self._sessions[session_token]

    def get_current_user(self, session_token):
        with self._lock:
            user_id = self._sessions.get(session_token)
            if not user_id:
                return None
            for user in self._users.values():
                if user.user_id == user_id:
                    return user
            return None

    def is_authenticated(self, session_token):
        with self._lock:
            return session_token in self._sessions


# --- Shape and Texture Tools ---

class ShapeType(Enum):
    RECTANGLE = "rectangle"
    CIRCLE = "circle"
    TRIANGLE = "triangle"
    LINE = "line"
    POLYGON = "polygon"
    ELLIPSE = "ellipse"


@dataclass
class Point:
    x: float
    y: float


@dataclass
class Texture:
    texture_id: str
    name: str
    pattern: str
    color: str
    opacity: float = 1.0
    scale: float = 1.0


@dataclass
class Shape:
    shape_id: str
    shape_type: ShapeType
    position: Point
    width: float
    height: float
    rotation: float = 0.0
    fill_color: str = "#FFFFFF"
    stroke_color: str = "#000000"
    stroke_width: float = 1.0
    texture: Optional[Texture] = None
    z_index: int = 0
    created_by: str = ""
    created_at: float = field(default_factory=time.time)
    group_id: Optional[str] = None
    locked: bool = False


class ShapeTools:
    """Provides tools for creating and editing geometric shapes."""

    def __init__(self, dependency_manager):
        self._dependency_manager = dependency_manager
        self._shapes = {}
        self._lock = threading.Lock()

    def _check_active(self):
        if not self._dependency_manager.is_active("shape_tools"):
            raise DependencyError("Shape tools are not yet active.")

    def create_shape(self, shape_type, x, y, width, height, created_by=""):
        self._check_active()
        with self._lock:
            shape_id = str(uuid.uuid4())
            shape = Shape(
                shape_id=shape_id,
                shape_type=shape_type,
                position=Point(x, y),
                width=width,
                height=height,
                created_by=created_by,
            )
            self._shapes[shape_id] = shape
            return shape

    def edit_shape(self, shape_id, **kwargs):
        self._check_active()
        with self._lock:
            shape = self._shapes.get(shape_id)
            if not shape:
                raise ValueError(f"Shape '{shape_id}' not found.")
            if shape.locked:
                raise ValueError(f"Shape '{shape_id}' is locked.")
            for key, value in kwargs.items():
                if hasattr(shape, key) and key not in ("shape_id", "created_at"):
                    setattr(shape, key, value)
            return shape

    def delete_shape(self, shape_id):
        self._check_active()
        with self._lock:
            if shape_id not in self._shapes:
                raise ValueError(f"Shape '{shape_id}' not found.")
            del self._shapes[shape_id]

    def get_shape(self, shape_id):
        self._check_active()
        with self._lock:
            return self._shapes.get(shape_id)

    def list_shapes(self):
        self._check_active()
        with self._lock:
            return list(self._shapes.values())


class TextureTools:
    """Provides tools for creating and applying textures to shapes."""

    def __init__(self, dependency_manager, shape_tools):
        self._dependency_manager = dependency_manager
        self._shape_tools = shape_tools
        self._textures = {}
        self._lock = threading.Lock()

    def _check_active(self):
        if not self._dependency_manager.is_active("shape_tools"):
            raise DependencyError("Shape tools must be active before using textures.")

    def create_texture(self, name, pattern, color, opacity=1.0, scale=1.0):
        self._check_active()
        with self._lock:
            texture_id = str(uuid.uuid4())
            texture = Texture(
                texture_id=texture_id,
                name=name,
                pattern=pattern,
                color=color,
                opacity=opacity,
                scale=scale,
            )
            self._textures[texture_id] = texture
            return texture

    def apply_texture(self, shape_id, texture_id):
        self._check_active()
        with self._lock:
            texture = self._textures.get(texture_id)
            if not texture:
                raise ValueError(f"Texture '{texture_id}' not found.")
        shape = self._shape_tools.get_shape(shape_id)
        if not shape:
            raise ValueError(f"Shape '{shape_id}' not found.")
        self._shape_tools.edit_shape(shape_id, texture=texture)
        return shape

    def remove_texture(self, shape_id):
        self._check_active()
        self._shape_tools.edit_shape(shape_id, texture=None)

    def get_texture(self, texture_id):
        self._check_active()
        with self._lock:
            return self._textures.get(texture_id)

    def list_textures(self):
        self._check_active()
        with self._lock:
            return list(self._textures.values())


# --- Real-Time Collaboration Canvas ---

class CanvasEvent(Enum):
    SHAPE_ADDED = "shape_added"
    SHAPE_MODIFIED = "shape_modified"
    SHAPE_DELETED = "shape_deleted"
    TEXTURE_APPLIED = "texture_applied"
    ANNOTATION_ADDED = "annotation_added"
    USER_JOINED = "user_joined"
    USER_LEFT = "user_left"
    CURSOR_MOVED = "cursor_moved"


@dataclass
class CanvasUpdate:
    event_type: CanvasEvent
    user_id: str
    data: dict
    timestamp: float = field(default_factory=time.time)
    update_id: str = field(default_factory=lambda: str(uuid.uuid4()))


class CollaborationCanvas:
    """Shared digital canvas enabling real-time collaborative design."""

    def __init__(self, dependency_manager, auth_system):
        self._dependency_manager = dependency_manager
        self._auth_system = auth_system
        self._participants = {}
        self._update_history = []
        self._listeners = {}
        self._cursors = {}
        self._lock = threading.Lock()

    def _check_active(self):
        if not self._dependency_manager.is_active("collaboration_canvas"):
            raise DependencyError("Collaboration canvas is not yet active.")

    def join(self, session_token):
        self._check_active()
        user = self._auth_system.get_current_user(session_token)
        if not user:
            raise ValueError("Invalid session. Please log in.")
        with self._lock:
            self._participants[user.user_id] = user
            self._cursors[user.user_id] = Point(0, 0)
        self._broadcast(CanvasEvent.USER_JOINED, user.user_id, {
            "username": user.username
        })
        return user

    def leave(self, session_token):
        self._check_active()
        user = self._auth_system.get_current_user(session_token)
        if not user:
            return
        with self._lock:
            self._participants.pop(user.user_id, None)
            self._cursors.pop(user.user_id, None)
        self._broadcast(CanvasEvent.USER_LEFT, user.user_id, {
            "username": user.username
        })

    def move_cursor(self, session_token, x, y):
        self._check_active()
        user = self._auth_system.get_current_user(session_token)
        if not user:
            raise ValueError("Invalid session.")
        with self._lock:
            self._cursors[user.user_id] = Point(x, y)
        self._broadcast(CanvasEvent.CURSOR_MOVED, user.user_id, {
            "x": x, "y": y
        })

    def get_participants(self):
        self._check_active()
        with self._lock:
            return list(self._participants.values())

    def get_cursors(self):
        self._check_active()
        with self._lock:
            return dict(self._cursors)

    def subscribe(self, user_id, callback):
        with self._lock:
            if user_id not in self._listeners:
                self._listeners[user_id] = []
            self._listeners[user_id].append(callback)

    def unsubscribe(self, user_id):
        with self._lock:
            self._listeners.pop(user_id, None)

    def _broadcast(self, event_type, user_id, data):
        update = CanvasUpdate(
            event_type=event_type,
            user_id=user_id,
            data=data,
        )
        with self._lock:
            self._update_history.append(update)
            listeners = dict(self._listeners)
        for uid, callbacks in listeners.items():
            if uid != user_id:
                for callback in callbacks:
                    try:
                        callback(update)
                    except Exception:
                        pass

    def notify_shape_added(self, user_id, shape):
        self._broadcast(CanvasEvent.SHAPE_ADDED, user_id, {
            "shape_id": shape.shape_id,
            "shape_type": shape.shape_type.value,
        })

    def notify_shape_modified(self, user_id, shape):
        self._broadcast(CanvasEvent.SHAPE_MODIFIED, user_id, {
            "shape_id": shape.shape_id,
        })

    def notify_shape_deleted(self, user_id, shape_id):
        self._broadcast(CanvasEvent.SHAPE_DELETED, user_id, {
            "shape_id": shape_id,
        })

    def get_history(self, since=None):
        self._check_active()
        with self._lock:
            if since is None:
                return list(self._update_history)
            return [u for u in self._update_history if u.timestamp >= since]


# --- Element Management and Organization ---

@dataclass
class ElementGroup:
    group_id: str
    name: str
    shape_ids: list = field(default_factory=list)
    created_by: str = ""
    locked: bool = False


class ElementManager:
    """Manages alignment, grouping, and arrangement of design elements."""

    def __init__(self, dependency_manager, shape_tools):
        self._dependency_manager = dependency_manager
        self._shape_tools = shape_tools
        self._groups = {}
        self._lock = threading.Lock()

    def _check_active(self):
        if not self._dependency_manager.is_active("element_management"):
            raise DependencyError(
                "Element management is not active. "
                "Shape tools must be operational first."
            )

    def align_shapes(self, shape_ids, alignment="left"):
        self._check_active()
        shapes = [self._shape_tools.get_shape(sid) for sid in shape_ids]
        shapes = [s for s in shapes if s is not None]
        if not shapes:
            return []

        if alignment == "left":
            min_x = min(s.position.x for s in shapes)
            for shape in shapes:
                self._shape_tools.edit_shape(
                    shape.shape_id, position=Point(min_x, shape.position.y)
                )
        elif alignment == "right":
            max_x = max(s.position.x + s.width for s in shapes)
            for shape in shapes:
                new_x = max_x - shape.width
                self._shape_tools.edit_shape(
                    shape.shape_id, position=Point(new_x, shape.position.y)
                )
        elif alignment == "top":
            min_y = min(s.position.y for s in shapes)
            for shape in shapes:
                self._shape_tools.edit_shape(
                    shape.shape_id, position=Point(shape.position.x, min_y)
                )
        elif alignment == "bottom":
            max_y = max(s.position.y + s.height for s in shapes)
            for shape in shapes:
                new_y = max_y - shape.height
                self._shape_tools.edit_shape(
                    shape.shape_id, position=Point(shape.position.x, new_y)
                )
        elif alignment == "center_h":
            avg_x = sum(s.position.x + s.width / 2 for s in shapes) / len(shapes)
            for shape in shapes:
                new_x = avg_x - shape.width / 2
                self._shape_tools.edit_shape(
                    shape.shape_id, position=Point(new_x, shape.position.y)
                )
        elif alignment == "center_v":
            avg_y = sum(s.position.y + s.height / 2 for s in shapes) / len(shapes)
            for shape in shapes:
                new_y = avg_y - shape.height / 2
                self._shape_tools.edit_shape(
                    shape.shape_id, position=Point(shape.position.x, new_y)
                )
        return shapes

    def group_shapes(self, shape_ids, name="Untitled Group", created_by=""):
        self._check_active()
        with self._lock:
            group_id = str(uuid.uuid4())
            group = ElementGroup(
                group_id=group_id,
                name=name,
                shape_ids=list(shape_ids),
                created_by=created_by,
            )
            self._groups[group_id] = group
            for sid in shape_ids:
                self._shape_tools.edit_shape(sid, group_id=group_id)
            return group

    def ungroup(self, group_id):
        self._check_active()
        with self._lock:
            group = self._groups.get(group_id)
            if not group:
                raise ValueError(f"Group '{group_id}' not found.")
            for sid in group.shape_ids:
                try:
                    self._shape_tools.edit_shape(sid, group_id=None)
                except ValueError:
                    pass
            del self._groups[group_id]

    def bring_to_front(self, shape_id):
        self._check_active()
        shapes = self._shape_tools.list_shapes()
        if not shapes:
            return
        max_z = max(s.z_index for s in shapes)
        self._shape_tools.edit_shape(shape_id, z_index=max_z + 1)

    def send_to_back(self, shape_id):
        self._check_active()
        shapes = self._shape_tools.list_shapes()
        if not shapes:
            return
        min_z = min(s.z_index for s in shapes)
        self._shape_tools.edit_shape(shape_id, z_index=min_z - 1)

    def distribute_horizontally(self, shape_ids):
        self._check_active()
        shapes = [self._shape_tools.get_shape(sid) for sid in shape_ids]
        shapes = [s for s in shapes if s is not None]
        if len(shapes) < 3:
            return shapes

        shapes.sort(key=lambda s: s.position.x)
        total_width = sum(s.width for s in shapes)
        span = (shapes[-1].position.x + shapes[-1].width) - shapes[0].position.x
        gap = (span - total_width) / (len(shapes) - 1)

        current_x = shapes[0].position.x
        for shape in shapes:
            self._shape_tools.edit_shape(
                shape.shape_id, position=Point(current_x, shape.position.y)
            )
            current_x += shape.width + gap
        return shapes

    def distribute_vertically(self, shape_ids):
        self._check_active()
        shapes = [self._shape_tools.get_shape(sid) for sid in shape_ids]
        shapes = [s for s in shapes if s is not None]
        if len(shapes) < 3:
            return shapes

        shapes.sort(key=lambda s: s.position.y)
        total_height = sum(s.height for s in shapes)
        span = (shapes[-1].position.y + shapes[-1].height) - shapes[0].position.y
        gap = (span - total_height) / (len(shapes) - 1)

        current_y = shapes[0].position.y
        for shape in shapes:
            self._shape_tools.edit_shape(
                shape.shape_id, position=Point(shape.position.x, current_y)
            )
            current_y += shape.height + gap
        return shapes

    def lock_shape(self, shape_id):
        self._check_active()
        self._shape_tools.edit_shape(shape_id, locked=True)

    def unlock_shape(self, shape_id):
        self._check_active()
        shape = self._shape_tools.get_shape(shape_id)
        if shape:
            shape.locked = False

    def get_group(self, group_id):
        self._check_active()
        with self._lock:
            return self._groups.get(group_id)

    def list_groups(self):
        self._check_active()
        with self._lock:
            return list(self._groups.values())


# --- Annotation and Commenting System ---

@dataclass
class Annotation:
    annotation_id: str
    shape_id: Optional[str]
    author_id: str
    author_name: str
    content: str
    position: Point
    created_at: float = field(default_factory=time.time)
    resolved: bool = False
    replies: list = field(default_factory=list)


@dataclass
class Reply:
    reply_id: str
    author_id: str
    author_name: str
    content: str
    created_at: float = field(default_factory=time.time)


class AnnotationSystem:
    """Enables annotating and commenting on design elements."""

    def __init__(self, dependency_manager, canvas):
        self._dependency_manager = dependency_manager
        self._canvas = canvas
        self._annotations = {}
        self._lock = threading.Lock()

    def _check_active(self):
        if not self._dependency_manager.is_active("annotation_system"):
            raise DependencyError(
                "Annotation system is not active. "
                "The collaboration canvas must be active first."
            )

    def add_annotation(self, author_id, author_name, content, x, y,
                       shape_id=None):
        self._check_active()
        with self._lock:
            annotation_id = str(uuid.uuid4())
            annotation = Annotation(
                annotation_id=annotation_id,
                shape_id=shape_id,
                author_id=author_id,
                author_name=author_name,
                content=content,
                position=Point(x, y),
            )
            self._annotations[annotation_id] = annotation
        self._canvas._broadcast(
            CanvasEvent.ANNOTATION_ADDED, author_id,
            {"annotation_id": annotation_id, "content": content}
        )
        return annotation

    def reply_to_annotation(self, annotation_id, author_id, author_name,
                            content):
        self._check_active()
        with self._lock:
            annotation = self._annotations.get(annotation_id)
            if not annotation:
                raise ValueError(f"Annotation '{annotation_id}' not found.")
            reply = Reply(
                reply_id=str(uuid.uuid4()),
                author_id=author_id,
                author_name=author_name,
                content=content,
            )
            annotation.replies.append(reply)
            return reply

    def resolve_annotation(self, annotation_id):
        self._check_active()
        with self._lock:
            annotation = self._annotations.get(annotation_id)
            if not annotation:
                raise ValueError(f"Annotation '{annotation_id}' not found.")
            annotation.resolved = True
            return annotation

    def delete_annotation(self, annotation_id):
        self._check_active()
        with self._lock:
            if annotation_id not in self._annotations:
                raise ValueError(f"Annotation '{annotation_id}' not found.")
            del self._annotations[annotation_id]

    def get_annotations_for_shape(self, shape_id):
        self._check_active()
        with self._lock:
            return [
                a for a in self._annotations.values()
                if a.shape_id == shape_id
            ]

    def get_all_annotations(self):
        self._check_active()
        with self._lock:
            return list(self._annotations.values())

    def get_unresolved_annotations(self):
        self._check_active()
        with self._lock:
            return [
                a for a in self._annotations.values() if not a.resolved
            ]


# --- Main Application ---

class CollaborativeDesignSuite:
    """
    Multi-agent collaborative design tool enabling teams to work together
    on a shared digital canvas with real-time updates, shape/texture tools,
    element management, and annotations.
    """

    def __init__(self):
        self.dependency_manager = DependencyManager()
        self._register_features()

        self.auth = AuthenticationSystem()
        self.shape_tools = ShapeTools(self.dependency_manager)
        self.texture_tools = TextureTools(self.dependency_manager, self.shape_tools)
        self.canvas = CollaborationCanvas(self.dependency_manager, self.auth)
        self.element_manager = ElementManager(
            self.dependency_manager, self.shape_tools
        )
        self.annotation_system = AnnotationSystem(
            self.dependency_manager, self.canvas
        )

        self._initialize_system()

    def _register_features(self):
        self.dependency_manager.register_feature("authentication", [])
        self.dependency_manager.register_feature(
            "collaboration_canvas", ["authentication"]
        )
        self.dependency_manager.register_feature(
            "shape_tools", ["authentication"]
        )
        self.dependency_manager.register_feature(
            "element_management", ["shape_tools"]
        )
        self.dependency_manager.register_feature(
            "annotation_system", ["collaboration_canvas"]
        )

    def _initialize_system(self):
        self.dependency_manager.activate_feature("authentication")
        self.dependency_manager.activate_feature("shape_tools")
        self.dependency_manager.activate_feature("collaboration_canvas")
        self.dependency_manager.activate_feature("element_management")
        self.dependency_manager.activate_feature("annotation_system")

    def register_user(self, username, password, email):
        return self.auth.register(username, password, email)

    def login_user(self, username, password):
        return self.auth.login(username, password)

    def logout_user(self, session_token):
        self.canvas.leave(session_token)
        self.auth.logout(session_token)

    def join_canvas(self, session_token):
        return self.canvas.join(session_token)

    def leave_canvas(self, session_token):
        self.canvas.leave(session_token)

    def create_shape(self, session_token, shape_type, x, y, width, height):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        shape = self.shape_tools.create_shape(
            shape_type, x, y, width, height, created_by=user.user_id
        )
        self.canvas.notify_shape_added(user.user_id, shape)
        return shape

    def edit_shape(self, session_token, shape_id, **kwargs):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        shape = self.shape_tools.edit_shape(shape_id, **kwargs)
        self.canvas.notify_shape_modified(user.user_id, shape)
        return shape

    def delete_shape(self, session_token, shape_id):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        self.shape_tools.delete_shape(shape_id)
        self.canvas.notify_shape_deleted(user.user_id, shape_id)

    def apply_texture(self, session_token, shape_id, texture_id):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        return self.texture_tools.apply_texture(shape_id, texture_id)

    def create_texture(self, session_token, name, pattern, color,
                       opacity=1.0, scale=1.0):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        return self.texture_tools.create_texture(
            name, pattern, color, opacity, scale
        )

    def align_shapes(self, session_token, shape_ids, alignment="left"):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        return self.element_manager.align_shapes(shape_ids, alignment)

    def group_shapes(self, session_token, shape_ids, name="Untitled Group"):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        return self.element_manager.group_shapes(
            shape_ids, name, created_by=user.user_id
        )

    def ungroup_shapes(self, session_token, group_id):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        self.element_manager.ungroup(group_id)

    def add_annotation(self, session_token, content, x, y, shape_id=None):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        return self.annotation_system.add_annotation(
            user.user_id, user.username, content, x, y, shape_id
        )

    def reply_to_annotation(self, session_token, annotation_id, content):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        return self.annotation_system.reply_to_annotation(
            annotation_id, user.user_id, user.username, content
        )

    def resolve_annotation(self, session_token, annotation_id):
        user = self.auth.get_current_user(session_token)
        if not user:
            raise ValueError("Authentication required.")
        return self.annotation_system.resolve_annotation(annotation_id)

    def get_feature_status(self):
        features = [
            "authentication", "collaboration_canvas", "shape_tools",
            "element_management", "annotation_system"
        ]
        return {f: self.dependency_manager.get_state(f).value for f in features}


# --- Demo / Self-Test ---

def main():
    """Demonstrate the CollaborativeDesignSuite functionality."""
    suite = CollaborativeDesignSuite()

    print("=== CollaborativeDesignSuite Demo ===\n")

    # Feature status
    print("Feature Status:")
    for feature, state in suite.get_feature_status().items():
        print(f"  {feature}: {state}")
    print()

    # Register users
    user1 = suite.register_user("alice", "password123", "alice@design.co")
    user2 = suite.register_user("bob", "securepass", "bob@design.co")
    print(f"Registered: {user1.username}, {user2.username}")

    # Login
    token1 = suite.login_user("alice", "password123")
    token2 = suite.login_user("bob", "securepass")
    print(f"Logged in: alice (token: {token1[:8]}...), bob (token: {token2[:8]}...)")

    # Join canvas
    suite.join_canvas(token1)
    suite.join_canvas(token2)
    participants = suite.canvas.get_participants()
    print(f"Canvas participants: {[p.username for p in participants]}\n")

    # Create shapes
    rect = suite.create_shape(token1, ShapeType.RECTANGLE, 10, 10, 100, 50)
    circle = suite.create_shape(token2, ShapeType.CIRCLE, 150, 30, 60, 60)
    triangle = suite.create_shape(token1, ShapeType.TRIANGLE, 250, 10, 80, 70)
    print(f"Created shapes: rectangle({rect.shape_id[:8]}), "
          f"circle({circle.shape_id[:8]}), triangle({triangle.shape_id[:8]})")

    # Create and apply texture
    texture = suite.create_texture(token1, "Dots", "polka_dot", "#FF5733")
    suite.apply_texture(token1, rect.shape_id, texture.texture_id)
    print(f"Applied texture '{texture.name}' to rectangle")

    # Align shapes
    suite.align_shapes(
        token1, [rect.shape_id, circle.shape_id, triangle.shape_id], "top"
    )
    print("Aligned all shapes to top")

    # Group shapes
    group = suite.group_shapes(
        token1, [rect.shape_id, circle.shape_id], "Header Elements"
    )
    print(f"Grouped shapes into '{group.name}' (id: {group.group_id[:8]})")

    # Annotations
    ann = suite.add_annotation(
        token2, "Consider using a warmer color here",
        15, 65, shape_id=rect.shape_id
    )
    print(f"\nAnnotation by bob: '{ann.content}'")

    reply = suite.reply_to_annotation(
        token1, ann.annotation_id, "Good idea, I'll update the palette"
    )
    print(f"Reply by alice: '{reply.content}'")

    suite.resolve_annotation(token1, ann.annotation_id)
    print("Annotation resolved.")

    # Element ordering
    suite.element_manager.bring_to_front(circle.shape_id)
    suite.element_manager.send_to_back(rect.shape_id)
    print("\nReordered: circle to front, rectangle to back")

    # Logout
    suite.logout_user(token1)
    suite.logout_user(token2)
    print("\nAll users logged out. Demo complete.")


if __name__ == "__main__":
    main()
